module RefModule(
   input clk,
   input rst,
   input enable,
   output reg [3:0] out
);reg [3:0] unused_count;
reg [3:0] next_count;

always @ (posedge clk) begin
   if (rst) begin
      unused_count <= 4'b0;
   end else begin
      unused_count <= next_count;
   end
end

always @ (*) begin
   if (enable) begin
      next_count = unused_count + 4'b1;
   end else begin
      next_count = unused_count;
   end
end

assign out = unused_count;

endmodule
